@app.on_event("shutdown")
async def shutdown():
    """Close Redis connection pool on shutdown."""
    global redis_pool
    if redis_pool:
        await redis_pool.close()


async def validate_token(
    credentials: HTTPAuthorizationCredentials = Depends(security),
    redis_conn: redis.Redis = Depends(get_redis),
) -> TokenData:
    """
    Dependency that validates OAuth 2.0 bearer tokens.
    
    Extracts the token from the Authorization header,
    looks it up in Redis cache, and returns the associated token data.
    
    Raises HTTPException 401 if token is missing, invalid, or expired.
    """
    token = credentials.credentials

    if not token:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Bearer token is required",
            headers={"WWW-Authenticate": "Bearer"},
        )

    try:
        token_key = f"oauth2:token:{token}"
        token_data_raw = await redis_conn.get(token_key)
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"Token validation service unavailable: {str(e)}",
        )

    if token_data_raw is None:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid or expired token",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    try:
        token_dict = json.loads(token_data_raw)
        token_data = TokenData(**token_dict)
    except (json.JSONDecodeError, ValueError) as e:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Malformed token data",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    # Check expiration explicitly (belt and suspenders with Redis TTL)
    expires_at = datetime.fromisoformat(token_data.expires_at)
    if datetime.utcnow() > expires_at:
        # Clean up expired token
        try:
            await redis_conn.delete(f"oauth2:token:{token}")
        except redis.RedisError:
            pass
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Token has expired",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    return token_data


def require_scopes(*required_scopes: str):
    """
    Factory for creating scope-checking dependencies.
    
    Returns a dependency that validates the token has all required scopes.
    """
    async def scope_checker(token_data: TokenData = Depends(validate_token)) -> TokenData:
        missing_scopes = set(required_scopes) - set(token_data.scopes)
        if missing_scopes:
            raise HTTPException(
                status_code=status.HTTP_403_FORBIDDEN,
                detail=f"Insufficient scopes. Missing: {', '.join(missing_scopes)}",
                headers={
                    "WWW-Authenticate": f'Bearer error="insufficient_scope" scope="{" ".join(required_scopes)}"'
                },
            )
        return token_data

    return scope_checker


